INSERT INTO `yl_material` (`id`, `name`, `description`, `price`, `stock`, `category`, `cover_img`, `file_url`, `specs`, `status`, `sales`, `file_size`, `download_count`, `tags`, `apply_year`, `author`, `rating`, `preview_content`, `file_format`, `create_time`, `update_time`, `deleted`) VALUES
(1, '考研数学一历年真题详解', '收录2015-2025年考研数学一全部真题，每道题配有详细解析和多种解法，适合基础阶段和冲刺阶段使用。', 68.00, 500, '公共课', 'https://picsum.photos/400/300?random=1', '/files/math1_zhenti.pdf', 'PDF电子版', 1, 128, '25.6MB', 356, '数学,真题,数一,解析', '2026', '李永乐团队', 4.8, '第一章：函数极限连续\n第二章：一元函数微分学\n第三章：一元函数积分学...', 'PDF', '2025-01-05 10:00:00', '2025-01-05 10:00:00', 0),
(2, '考研英语词汇闪过', '按考频分类的考研英语词汇书，高频词、中频词、低频词分类记忆，配有真题例句和记忆方法。', 45.00, 800, '公共课', 'https://picsum.photos/400/300?random=2', '/files/english_vocabulary.pdf', 'PDF电子版', 1, 256, '18.3MB', 512, '英语,词汇,单词,记忆', '2026', '刘晓艳', 4.6, '高频词汇（出现10次以上）\n中频词汇（出现5-10次）\n低频词汇（出现1-4次）...', 'PDF', '2025-01-08 14:00:00', '2025-01-08 14:00:00', 0),
(3, '考研政治核心考点精讲', '肖秀荣团队出品，涵盖马原、毛中特、史纲、思修全部核心考点，配有思维导图和记忆口诀。', 55.00, 600, '公共课', 'https://picsum.photos/400/300?random=3', '/files/political_core.pdf', 'PDF电子版', 1, 189, '32.1MB', 423, '政治,考点,精讲,肖秀荣', '2026', '肖秀荣团队', 4.9, '马克思主义基本原理概论\n毛泽东思想和中国特色社会主义理论体系概论...', 'PDF', '2025-01-10 09:00:00', '2025-01-10 09:00:00', 0),
(4, '数据结构1800题', '计算机考研必备，涵盖线性表、栈队列、树、图、查找排序全部考点，每章配有知识点总结和习题。', 50.00, 400, '专业课', 'https://picsum.photos/400/300?random=4', '/files/data_structure_1800.pdf', 'PDF电子版', 1, 98, '28.5MB', 267, '计算机,数据结构,习题,408', '2026', '王道论坛', 4.7, '第1章 绪论\n第2章 线性表\n第3章 栈和队列\n第4章 树与二叉树...', 'PDF', '2025-01-12 11:00:00', '2025-01-12 11:00:00', 0),
(5, '计算机网络考研复习笔记', '按OSI七层模型和TCP/IP四层模型整理，配有协议分析图和真题考点标注。', 30.00, 350, '专业课', 'https://picsum.photos/400/300?random=5', '/files/network_notes.pdf', 'PDF电子版', 1, 76, '15.2MB', 198, '计算机,网络,协议,408', '2026', '王道论坛', 4.5, '第1章 计算机网络体系结构\n第2章 物理层\n第3章 数据链路层...', 'PDF', '2025-01-15 15:00:00', '2025-01-15 15:00:00', 0),
(6, '考研英语作文万能模板', '涵盖小作文（书信、通知）和大作文（图画、图表）全部类型，提供万能句型和高级替换词。', 15.00, 1000, '公共课', 'https://picsum.photos/400/300?random=6', '/files/english_template.pdf', 'PDF电子版', 1, 312, '5.8MB', 678, '英语,作文,模板,写作', '2026', '王江涛', 4.4, '小作文模板：建议信、投诉信、邀请信、感谢信...\n大作文模板：图画描述、观点阐述...', 'PDF', '2025-01-20 10:00:00', '2025-01-20 10:00:00', 0),
(7, '高等数学辅导讲义', '汤家凤老师经典讲义，涵盖高数全部知识点，例题丰富，讲解细致，适合基础薄弱的同学。', 42.00, 450, '公共课', 'https://picsum.photos/400/300?random=7', '/files/math_advanced.pdf', 'PDF电子版', 1, 145, '35.2MB', 389, '数学,高数,讲义,基础', '2026', '汤家凤', 4.6, '第一章 函数与极限\n第二章 导数与微分\n第三章 微分中值定理...', 'PDF', '2025-02-01 09:00:00', '2025-02-01 09:00:00', 0),
(8, '操作系统考研指导', '涵盖进程管理、内存管理、文件系统、I/O系统全部考点，配有经典算法图解和真题演练。', 38.00, 300, '专业课', 'https://picsum.photos/400/300?random=8', '/files/os_guide.pdf', 'PDF电子版', 1, 67, '22.4MB', 156, '计算机,操作系统,408,算法', '2026', '王道论坛', 4.5, '第1章 操作系统概述\n第2章 进程管理\n第3章 内存管理...', 'PDF', '2025-02-05 14:00:00', '2025-02-05 14:00:00', 0),
(9, '线性代数辅导讲义', '李永乐老师经典讲义，从矩阵基础到特征值特征向量，循序渐进，例题经典。', 35.00, 500, '公共课', 'https://picsum.photos/400/300?random=9', '/files/linear_algebra.pdf', 'PDF电子版', 1, 112, '18.7MB', 298, '数学,线代,讲义,李永乐', '2026', '李永乐', 4.8, '第一章 行列式\n第二章 矩阵\n第三章 向量...', 'PDF', '2025-02-10 11:00:00', '2025-02-10 11:00:00', 0),
(10, '计算机组成原理复习全书', '涵盖数据表示、运算器、存储器、指令系统、CPU设计全部考点，配有大量图表辅助理解。', 48.00, 280, '专业课', 'https://picsum.photos/400/300?random=10', '/files/computer_org.pdf', 'PDF电子版', 1, 54, '30.1MB', 134, '计算机,组成原理,408,CPU', '2026', '王道论坛', 4.4, '第1章 计算机系统概述\n第2章 数据的表示和运算...', 'PDF', '2025-02-15 10:00:00', '2025-02-15 10:00:00', 0),
(11, '考研数学二历年真题详解', '收录2015-2025年考研数学二全部真题，适合不考概率论的同学使用。', 65.00, 400, '公共课', 'https://picsum.photos/400/300?random=11', '/files/math2_zhenti.pdf', 'PDF电子版', 1, 87, '23.4MB', 245, '数学,真题,数二,解析', '2026', '李永乐团队', 4.7, '第一章：函数极限连续\n第二章：一元函数微分学...', 'PDF', '2025-02-20 09:00:00', '2025-02-20 09:00:00', 0),
(12, '考研英语阅读理解精讲', '唐迟老师阅读方法论，涵盖细节题、主旨题、推理题、词义题全部解题技巧。', 39.00, 600, '公共课', 'https://picsum.photos/400/300?random=12', '/files/english_reading.pdf', 'PDF电子版', 1, 178, '20.5MB', 445, '英语,阅读,理解,技巧', '2026', '唐迟', 4.5, '第一章 阅读方法论概述\n第二章 细节题解题技巧...', 'PDF', '2025-03-01 14:00:00', '2025-03-01 14:00:00', 0);
INSERT INTO `yl_news` (`id`, `title`, `content`, `type`, `cover_img`, `view_count`, `status`, `comment_count`, `create_time`, `update_time`, `deleted`) VALUES
(1, '2026年考研报名时间公布', '教育部近日公布2026年全国硕士研究生招生考试报名时间：网上预报名时间为2025年9月24日至9月27日，正式报名时间为2025年10月5日至10月25日。考生需登录中国研究生招生信息网进行报名。', '考研动态', 'https://picsum.photos/800/400?random=101', 1256, 1, 8, '2025-03-01 10:00:00', '2025-03-01 10:00:00', 0),
(2, '清华大学计算机系2026年招生简章', '清华大学计算机科学与技术系2026年计划招收硕士研究生120人，其中推免生约80人。初试科目为：101思想政治理论、201英语一、301数学一、912计算机专业基础综合。', '院校信息', 'https://picsum.photos/800/400?random=102', 2341, 1, 15, '2025-03-05 14:00:00', '2025-03-05 14:00:00', 0),
(3, '考研数学复习规划：从基础到冲刺', '数学复习建议分为三个阶段：基础阶段（3-6月）以教材和基础讲义为主，强化阶段（7-9月）以习题集和真题为主，冲刺阶段（10-12月）以模拟题和错题为主。每个阶段都要做好笔记和错题整理。', '备考经验', 'https://picsum.photos/800/400?random=103', 3456, 1, 23, '2025-03-10 09:00:00', '2025-03-10 09:00:00', 0),
(4, '2026年考研国家线预测', '根据近年趋势分析，2026年考研国家线预计：哲学300分左右，经济学345分左右，法学330分左右，教育学325分左右，文学355分左右，历史学325分左右，理学290分左右，工学270分左右。', '考研动态', 'https://picsum.photos/800/400?random=104', 5678, 1, 45, '2025-03-15 11:00:00', '2025-03-15 11:00:00', 0),
(5, '如何高效背诵考研政治', '政治背诵建议：1. 先理解再记忆，不要死记硬背；2. 利用思维导图建立知识框架；3. 结合时政热点理解理论；4. 每天固定时间背诵，保持节奏；5. 利用碎片时间反复复习。', '备考经验', 'https://picsum.photos/800/400?random=105', 1890, 1, 12, '2025-03-20 15:00:00', '2025-03-20 15:00:00', 0),
(6, '北京大学软件与微电子学院招生信息', '北京大学软件与微电子学院2026年计划招收全日制硕士研究生200人，研究方向包括：软件工程、集成电路工程、电子与通信工程、集成电路科学与工程等。', '院校信息', 'https://picsum.photos/800/400?random=106', 1567, 1, 9, '2025-03-25 10:00:00', '2025-03-25 10:00:00', 0);
INSERT INTO `yl_guide` (`id`, `title`, `content`, `category`, `cover_img`, `view_count`, `status`, `institution`, `major`, `comment_count`, `create_time`, `update_time`, `deleted`) VALUES
(1, '2026计算机考研408复习全攻略', '计算机专业基础综合（408）涵盖数据结构、计算机组成原理、操作系统、计算机网络四门课程。复习建议：1. 数据结构：重点掌握线性表、树、图、查找排序算法；2. 组成原理：重点掌握数据表示、运算器、存储器、指令系统；3. 操作系统：重点掌握进程管理、内存管理、文件系统；4. 计算机网络：重点掌握OSI模型、TCP/IP协议栈。推荐复习顺序：数据结构→组成原理→操作系统→计算机网络。', '计算机', 'https://picsum.photos/800/400?random=201', 3421, 1, '多校适用', '计算机科学与技术', 18, '2025-01-20 10:00:00', '2025-01-20 10:00:00', 0),
(2, '跨专业考研计算机经验分享', '本人本科英语专业，跨考计算机成功上岸。经验分享：1. 数学是重中之重，建议提前一年开始复习；2. 专业课零基础不可怕，王道四本书+真题足够；3. 编程能力需要提前培养，建议刷LeetCode；4. 复试需要准备上机考试，建议提前练习。', '跨考经验', 'https://picsum.photos/800/400?random=202', 2156, 1, '多校适用', '计算机科学与技术', 25, '2025-02-05 14:00:00', '2025-02-05 14:00:00', 0),
(3, '考研英语一85分经验贴', '英语一85分经验：1. 单词是基础，每天坚持背200个；2. 阅读是核心，每天做2篇真题阅读；3. 作文要准备模板，但不要完全依赖；4. 翻译和新题型也要重视；5. 留近3年真题做模拟。推荐资料：词汇闪过+黄皮书真题+王江涛作文。', '英语备考', 'https://picsum.photos/800/400?random=203', 4567, 1, '多校适用', '不限专业', 32, '2025-02-15 09:00:00', '2025-02-15 09:00:00', 0),
(4, '清华大学计算机系复试经验', '清华计算机复试包括：1. 笔试（数据结构与算法、计算机系统结构）；2. 机试（3道编程题，难度中等）；3. 面试（专业问题+英语口语+综合素质）。建议：1. 提前准备机试，熟悉OJ系统；2. 复习本科核心课程；3. 准备科研项目介绍；4. 练习英语口语。', '复试经验', 'https://picsum.photos/800/400?random=204', 1876, 1, '清华大学', '计算机科学与技术', 14, '2025-03-01 11:00:00', '2025-03-01 11:00:00', 0),
(5, '考研数学复习时间安排表', '数学复习时间安排：3-6月基础阶段（每天4小时）：高数教材+汤家凤基础班；7-8月强化阶段（每天5小时）：李永乐复习全书+强化班；9-10月真题阶段（每天4小时）：近15年真题，每套限时3小时；11-12月冲刺阶段（每天3小时）：模拟题+错题回顾。', '数学备考', 'https://picsum.photos/800/400?random=205', 2890, 1, '多校适用', '不限专业', 21, '2025-03-10 15:00:00', '2025-03-10 15:00:00', 0);
INSERT INTO `yl_post` (`id`, `title`, `content`, `user_id`, `nickname`, `avatar`, `view_count`, `like_count`, `comment_count`, `category`, `status`, `is_top`, `create_time`, `update_time`, `deleted`) VALUES
(1, '【经验贴】三个月逆袭985，我是怎么做到的', '先介绍一下背景：本科双非，一战某985失败，二战成功上岸。第一年总分差5分，第二年提高了40分。主要经验：1. 找准弱项，第一年数学只有90分，第二年提高到130分；2. 制定详细计划，每天学习10小时；3. 找研友互相监督；4. 保持良好心态。', 2, '张三', NULL, 1234, 56, 12, 4, 1, 0, '2025-02-15 10:00:00', '2025-02-15 10:00:00', 0),
(2, '数据结构二叉树算法总结', '整理了二叉树所有常考算法：1. 前中后序遍历（递归+迭代）；2. 层序遍历；3. 求树高；4. 判断平衡二叉树；5. 求最近公共祖先；6. 二叉搜索树验证。每种算法都附带了代码实现和时间复杂度分析。', 3, '李四', NULL, 876, 34, 8, 2, 1, 0, '2025-02-20 14:00:00', '2025-02-20 14:00:00', 0),
(3, '英语阅读总是错很多怎么办', '做了10年真题，阅读还是错8-10个，很焦虑。请问大家有什么提高阅读的方法吗？我已经背完一轮单词了，长难句也在看，但是做题还是找不到感觉。', 4, '王五', NULL, 654, 12, 15, 1, 1, 0, '2025-03-01 09:00:00', '2025-03-01 09:00:00', 0),
(4, '清华大学计算机复试会问什么问题', '请问有没有参加过清华计算机复试的学长学姐？想了解一下面试都会问什么类型的问题？专业问题难度大吗？英语面试是什么形式？', 2, '张三', NULL, 1567, 45, 22, 3, 1, 0, '2025-03-05 11:00:00', '2025-03-05 11:00:00', 0),
(5, '政治选择题技巧分享', '整理了政治选择题的解题技巧：1. 马原部分注意概念辨析；2. 毛中特注意时间节点；3. 史纲注意历史事件排序；4. 思修注意价值观导向。多选题要特别注意"全选"的情况，一般出现在思修和时政部分。', 5, '赵六', NULL, 432, 23, 6, 1, 1, 0, '2025-03-10 15:00:00', '2025-03-10 15:00:00', 0);
