INSERT INTO `yl_chat_message` (`id`, `user_id`, `session_id`, `role`, `content`, `create_time`, `update_time`, `deleted`) VALUES
(1, 2, 'sess-001-zhangsan', 1, '计算机专业考研怎么复习？', '2025-03-15 10:00:00', '2025-03-15 10:00:00', 0),
(2, 2, 'sess-001-zhangsan', 2, '计算机专业考研复习建议：\n1. 数学：重点复习高数、线代、概率论，推荐李永乐复习全书\n2. 专业课：408统考包括数据结构、组成原理、操作系统、计算机网络\n3. 英语：每天坚持背单词，真题至少做两遍\n4. 政治：9月开始不晚，肖秀荣系列足够\n\n需要我推荐具体的复习资料吗？', '2025-03-15 10:00:05', '2025-03-15 10:00:05', 0),
(3, 2, 'sess-001-zhangsan', 1, '推荐一下数据结构资料', '2025-03-15 10:05:00', '2025-03-15 10:05:00', 0),
(4, 2, 'sess-001-zhangsan', 2, '推荐以下数据结构资料：\n\n1. [数据结构1800题](path=/materials/4) - 50.00元\n   王道论坛出品，涵盖全部考点\n\n2. [计算机网络考研复习笔记](path=/materials/5) - 30.00元\n   配套使用效果更佳\n\n建议先看书再做习题，循序渐进。', '2025-03-15 10:05:03', '2025-03-15 10:05:03', 0),
(5, 3, 'sess-002-lisi', 1, '考研政治怎么复习？', '2025-03-16 09:00:00', '2025-03-16 09:00:00', 0),
(6, 3, 'sess-002-lisi', 2, '考研政治复习建议：\n1. 时间规划：9-10月基础，11月强化，12月冲刺\n2. 资料推荐：肖秀荣精讲精练+1000题+肖四肖八\n3. 学习方法：先看书再做题，错题要反复看\n4. 时政：12月集中背诵，关注全年热点\n\n政治是性价比最高的科目，投入产出比很高！', '2025-03-16 09:00:04', '2025-03-16 09:00:04', 0);
